CREATE TABLE IF NOT EXISTS course_registrations (registration_id INT AUTO_INCREMENT PRIMARY KEY, student_id INT NOT NULL, course_id INT NOT NULL, registered_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY student_course (student_id, course_id), FOREIGN KEY (student_id) REFERENCES students(student_id) ON DELETE CASCADE, FOREIGN KEY (course_id) REFERENCES courses(course_id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
